svg.script:
//!export-start
let _pn_position = 0;
let _pn_weight = 0;
let _pb_active = false;
//!export-end

function putValue(id, value) {
    if (id === '_pn_position') {
        const pkg = document.getElementById('package-group');
        if (pkg) {
            // Map 0-100 to 25px - 245px (track range)
            const x = 25 + (value * 2.2);
            pkg.setAttribute('transform', `translate(${x}, 15)`);
        }
    }
    if (id === '_pn_weight') {
        const rect = document.getElementById('package-rect');
        if (rect) {
            // Change to Orange if weight detected
            rect.style.fill = (parseFloat(value) > 0) ? '#e67e22' : '#3498db';
        }
    }
    if (id === '_pb_active') {
        const rollers = document.querySelectorAll('.roller');
        rollers.forEach(r => {
            r.style.animationPlayState = value ? 'running' : 'paused';
        });
    }
}

// FUXA Cleanup Logic
const svgId = 'fuxa_conveyor_01';
const observer = new MutationObserver((mutations) => {
    mutations.forEach((mutation) => {
        mutation.removedNodes.forEach((node) => {
            if (node.id === svgId) {
                observer.disconnect();
            }
        });
    });
});
observer.observe(document.body, { childList: true, subtree: true });
